class Solution {
public:
    bool isRationalEqual(string s, string t) {
        return normalize(s) == normalize(t);
    }

    double normalize(string s) {
        size_t pos = s.find('(');
        if (pos != string::npos) {
            string base = s.substr(0, pos);
            string rep = s.substr(pos + 1, s.size() - pos - 2);
            return stod(base + repeat(rep, 20));
        } else {
            return stod(s);
        }
    }

    string repeat(string s, int n) {
        string res;
        for (int i = 0; i < n; ++i) {
            res += s;
        }
        return res;
    }
};
